#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        unsigned long long N,M; scanf("%llu %llu",&N,&M);
        unsigned long long extra[64]; int cnt=0;
        for(int b=0;b<61;b++){
            if(((N>>b)&1ULL)==0ULL){
                unsigned long long cand = N | (1ULL<<b);
                if(cand<=M) extra[cnt++]=cand;
            }
        }
        if(cnt==0){
            printf("-1\n");
        }else{
            printf("%d\n",cnt+1);
            printf("%llu",N);
            for(int i=0;i<cnt;i++) printf(" %llu",extra[i]);
            printf("\n");
        }
    }
    return 0;
}

