import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        extra = []
        for b in range(61):
            if (N >> b) & 1 == 0:
                cand = N | (1 << b)
                if cand <= M:
                    extra.append(cand)
        if not extra:
            out_lines.append('-1')
        else:
            out_lines.append(str(len(extra)+1))
            seq = [str(N)] + [str(x) for x in extra]
            out_lines.append(' '.join(seq))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

