let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = BigInt(input[idx++]);
  const M = BigInt(input[idx++]);
  let extra = [];
  for (let b = 0n; b <= 60n; b++) {
    if ((N >> b) & 1n) continue; // bit is 1, skip
    const cand = N | (1n << b);
    if (cand <= M) extra.push(cand);
  }
  if (extra.length === 0) {
    out.push('-1');
  } else {
    out.push(String(extra.length + 1));
    const seq = [N.toString(), ...extra.map(v => v.toString())].join(' ');
    out.push(seq);
  }
}
